from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector

qc = QuantumCircuit(2)
qc.h(0)
qc.x(1)
sv = Statevector.from_instruction(qc)
ampl = {str(k): v for k, v in sv.to_dict().items()}
nonzero = {k for k, v in ampl.items() if abs(v) > 1e-9}

opt = {"A": "00", "B": "01", "C": "10", "D": "11"}
evidence = {}
proven = []
for k, b in opt.items():
    mag = round(abs(ampl.get(b, 0)), 4)
    present = b in nonzero
    evidence[k] = f"basis |{b}>: |amplitude|={mag} -> node present={present}"
    if present:
        proven.append(k)

emit_verdict({
    "answer": proven,
    "evidence": evidence,
    "observed": {"nonzero_basis": sorted(nonzero)},
})
